children.text:
section
  {
    border: black solid 2px;
    float: left;
    font-family: monospace;
    font-size: 14px;
    line-height: 1; /* computes to 14px */
    margin-bottom: 10px;
    width: 16ch;
  }

section.applies-to-text
  {
    clear: both;
  }

section.applies-to-inline
  {
    margin-left: 10em;
  }

div
  {
    display: contents;
  }

div.first-subtest
  {
    white-space: normal;
  }

div.second-subtest
  {
    white-space: nowrap;
  }

div.third-subtest
  {
    white-space: pre;
  }

div.fourth-subtest
  {
    white-space: pre-wrap;
  }

div.fifth-subtest
  {
    white-space: break-spaces;
  }

div.sixth-subtest
  {
    white-space: pre-line;
  }

hr
  {
    clear: both;
    margin: 4em auto 1.5em 0em;
    width: 480px;
  }
